-- =============================================================================
-- 考研英语作文真题种子数据（2005-2025）
-- 英语一：2005-2025（小作文 task1 + 大作文 task2）
-- 英语二：2010-2025（小作文 task1 + 大作文 task2）
-- stage_id = 4 (postgrad)
-- 新增 image_description 列：task2 条目存放 "{caption}。{description}"
-- =============================================================================

-- 英语一 小作文（task1）
ON DUPLICATE KEY UPDATE
    title = VALUES(title),
    prompt_text = VALUES(prompt_text),
    image_url = VALUES(image_url),
    image_description = VALUES(image_description),
    material_text = VALUES(material_text),
    task = VALUES(task),
    source = VALUES(source),
    is_active = VALUES(is_active);

-- 英语一 大作文（task2）
ON DUPLICATE KEY UPDATE
    title = VALUES(title),
    prompt_text = VALUES(prompt_text),
    image_url = VALUES(image_url),
    image_description = VALUES(image_description),
    material_text = VALUES(material_text),
    task = VALUES(task),
    source = VALUES(source),
    is_active = VALUES(is_active);

